+   /**
+    * Validates that a path is safe and does not escape the base directory.
+    * 
+    * @param baseDir the base directory
+    * @param targetPath the target path to validate
+    * @return the validated path
+    * @throws IOException if the path is invalid or escapes the base directory
+    */
+   private static Path validatePath(Path baseDir, String targetPath) throws IOException
+   {
+      // Reject absolute paths and null/empty paths
+      if (targetPath == null || targetPath.isEmpty() || new File(targetPath).isAbsolute())
+      {
+         throw new IOException("Invalid path: " + targetPath);
+      }
+      
+      Path resolvedPath = baseDir.resolve(targetPath).normalize();
+      if (!resolvedPath.startsWith(baseDir.normalize()))
+      {
+         throw new IOException("Path traversal detected: " + targetPath);
+      }
+      return resolvedPath;
+   }

